import{c as a}from"./app.8935f5f1.js";const n={},s=a('<h2 id="数据持久化" tabindex="-1"><a class="header-anchor" href="#数据持久化" aria-hidden="true">#</a> 数据持久化</h2><p><code>cd nacos/conf/ application.properties</code></p><div class="language-properties ext-properties"><pre class="language-properties"><code>\n\n<span class="token attr-name">spring.datasource.platform</span><span class="token punctuation">=</span><span class="token attr-value">mysql</span>\n\n<span class="token comment">### Count of DB:</span>\n<span class="token attr-name">db.num</span><span class="token punctuation">=</span><span class="token attr-value">1</span>\n\n<span class="token comment">### Connect URL of DB:</span>\n<span class="token attr-name">db.url.0</span><span class="token punctuation">=</span><span class="token attr-value">jdbc:mysql://127.0.0.1:3306/nacos?characterEncoding=utf8&amp;connectTimeout=1000&amp;socketTimeout=3000&amp;autoReconnect=true&amp;useUnicode=true&amp;useSSL=false&amp;serverTimezone=UTC</span>\n<span class="token attr-name">db.user.0</span><span class="token punctuation">=</span><span class="token attr-value">root</span>\n<span class="token attr-name">db.password.0</span><span class="token punctuation">=</span><span class="token attr-value">0</span>\n\n<span class="token comment">### Connection pool configuration: hikariCP</span>\n<span class="token attr-name">db.pool.config.connectionTimeout</span><span class="token punctuation">=</span><span class="token attr-value">30000</span>\n<span class="token attr-name">db.pool.config.validationTimeout</span><span class="token punctuation">=</span><span class="token attr-value">10000</span>\n<span class="token attr-name">db.pool.config.maximumPoolSize</span><span class="token punctuation">=</span><span class="token attr-value">20</span>\n<span class="token attr-name">db.pool.config.minimumIdle</span><span class="token punctuation">=</span><span class="token attr-value">2</span>\n\n</code></pre></div><h3 id="启动-单节点" tabindex="-1"><a class="header-anchor" href="#启动-单节点" aria-hidden="true">#</a> 启动 单节点</h3><ul><li>nacos 默认启动为集群模式，</li><li><code> startup.cmd -m standalone</code> -m 单节点模式</li></ul>',5);n.render=function(a,n){return s};export{n as default};
